solution_code:
#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    std::cin.ignore();
    for (int i = 1; i <= n; ++i) {
        std::string line;
        std::getline(std::cin, line);
        std::cout << i << ": " << line << "\n";
    }
    return 0;
}

